// // This is a 1-to-4 demultiplexer that routes one of four 4-bit wide input data lines (A, B, C, D) to the output (Y) based on the values of two selection inputs (SEL0 and SEL1).
module top_module(
    input [3:0] A,
    input [3:0] B,
    input [3:0] C,
    input [3:0] D,
    input SEL0,
    input SEL1,
    output reg [3:0] Y
);always @ (SEL1 or SEL0 or A or B or C or D)
    case ({SEL1, SEL0})
        2'b00: Y = A;
        2'b01: Y = B;
        2'b10: Y = C;
        2'b11: Y = D;
    endcase

endmodule
